-----------------------------------------------------------------
---挂机光效

-----------------------------------------------------------------
---@class LFightIdleEffect
local LFightIdleEffect = LxClass("LFightIdleEffect",nil)
-----------------------------------------------------------------
LFightIdleEffect.BULLET_SCALE_TYPE = {
	[LSkillEffConst.BULLET_LINEAR_THREE] = true,
	[LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE] = true,
}

------------------------------------------------------------------
local LDisplayEffect = LDisplayEffect

local typeofBtObjectView = typeof(CardEHT.BtObjectView)
local typeofAnimator = typeof(UnityEngine.Animator)
local typeofParticleSystem = typeof(UnityEngine.ParticleSystem)
local typeOfSkeletonAnimation = typeof(Spine.Unity.SkeletonAnimation)
local typeofRenderer = typeof(UnityEngine.Renderer)

-----------------------------------------------------------------
function LFightIdleEffect:LFightIdleEffect(manager)
	--父节点
	self._parentTrans = nil
	--资源名字
	self._effectName = nil

	--开始播放时间
	self._startTime = 0
	--持续时间
	self._playTime = 0

	--显示对象
	self._dp = nil

	--是否正在播放
	self._isPlaying = false

	--已经加载完成
	self._isPreloaded = false

	--光效管理器创建的id
	self._index = 0

	self._pos = nil

	self._dir = LFightIdleConst.DIRECTION_RIGHT

	self._scaleSize = 1

	self._manager = manager
	
	self._layerName = nil

	---@type LFightIdleObject 特效bone作用对象
	self._targetObj = nil
	---@type string bone
	self._boneName = nil
end

function LFightIdleEffect:Create(idx,parentTrans,effId,pos,dir,startTime,playTime, dissipateTime)
	self._index = idx
	self._parentTrans = parentTrans

	if pos then
		pos = pos:Clone()
	else
		pos = Vector3(0,0,0)
	end
	self._pos = pos

	self._dir = dir

	self._effectName = effId

	self._startTime = self:GetTime() + startTime

	self._playTime = self._startTime + playTime

	self._dissipateTime = self._playTime + dissipateTime
end

function LFightIdleEffect:GetEffId()
	return self._effectName
end

function LFightIdleEffect:SetBullet(isBullet,bulletTarPos,bulletFlyTime,bulletTrack, index)
	self._isBullet = isBullet
	self._bulletTarPos = bulletTarPos
	self._bulletFlyTime = bulletFlyTime
	self._bulletTrack = bulletTrack or 0
	self._bulletIndex = index or 0
end

function LFightIdleEffect:SetBone(targetObj,boneName)
	self._targetObj = targetObj
	self._boneName = boneName
end

function LFightIdleEffect:SetScaleSize(scaleSize)
	self._scaleSize = scaleSize or 1
end

function LFightIdleEffect:SetMaskShow(bMask)
	if bMask then
		self._layerName = "ForeGround"
		if self._dp then
			self._dp:SetRenderLayer(self._layerName)
		end		
	else
		self._layerName = nil
	end
end

function LFightIdleEffect:SetLayerMask(mask)
	self._layerMask = mask
end

-----------------------------------------------------------------
function LFightIdleEffect:CircleArea(offset)
	self._pos = self._pos + offset
	if self._bulletTarPos then self._bulletTarPos = self._bulletTarPos + offset end

	if self._targetObj and not string.isempty(self._boneName) then return end

	if self._dp and self._dp:IsDpValid() then
		local dpTrans = self._dp:GetDisplayTrans()
		local nowPos = dpTrans.position
		nowPos = nowPos + offset
		self:SetPosition(nowPos)
		local comp  = dpTrans:GetComponent(typeofBtObjectView)
		if comp then
			comp:SetOffsetPos(offset)
		end
	end

end

function LFightIdleEffect:CheckNormalIsNeedAddBone()
	if not self._dp then return end

	if not self._targetObj or string.isempty(self._boneName) then return end

	local spineDp = self._targetObj:GetDpObject()
	if not spineDp then return end

	---@type LDisplayEffect
	local loadDp = self._dp
	loadDp:InternalInitBoneFollower(spineDp,self._boneName)
end
-----------------------------------------------------------------
function LFightIdleEffect:PlayEffect()
	if self._isPlaying then return end
	self._isPlaying = true
	if self._pdp then
		self._dp = self._pdp
		if self._isPreloaded then
			self:OnEffectLoaded()
			self:DoPlayEffect(true)
		end
		self._pdp = nil
	else
		local dp = LDisplayEffect:New()
		self._dp = dp
		dp:CreateEffect(self._parentTrans,self._effectName)
		dp:SetResTag(CS.RES_TAG_SCENE)
		dp:SetLoadedFunction(function()
			self:OnEffectLoaded()
		end)
		dp:StartLoadEffect()
	end
end

function LFightIdleEffect:OnEffectLoaded()
	local dir = self._dir
	if not self._dp:IsDpValid() then return end
	self:CheckNormalIsNeedAddBone()
	if self._layerName then
		self._dp:SetRenderLayer(self._layerName)
	end

	local dpTrans = self._dp:GetDisplayTrans()

	if self._layerMask then
		local dpGo = dpTrans.gameObject
		if dpGo.layer ~= self._layerMask then
			CS.UpdateChildLayer(dpTrans, self._layerMask)
		end
	end

	if dir == LFightIdleConst.DIRECTION_RIGHT then
		dpTrans.localEulerAngles = Vector3(0,0,0)
	else
		dpTrans.localEulerAngles = Vector3(0,180,0)
	end
	if self._pos then
		self:SetPosition(self._pos)
	end

	if self._speedUp then
		self:UpdateTimeScale(self._speedUp)
	end

	if self._scaleSize ~= 1 then
		dpTrans.localScale = Vector3(self._scaleSize,self._scaleSize,self._scaleSize)
	end

	--子弹
	if self._isBullet then
		local comp = dpTrans:GetComponent(typeofBtObjectView)
		if not comp then
			comp = dpTrans.gameObject:AddComponent(typeofBtObjectView)
		end
		local time = self:GetTime()
		local calcTime = time - self._startTime
		local flyTime = self._bulletFlyTime
		local bulletTarPos = self._bulletTarPos

		local bulletTrack = self._bulletTrack
		if bulletTrack >= 100 then --100以上是不带z旋转的
			comp:EnableAngle(false)
		else
			comp:EnableAngle(true)
		end

		if LFightIdleEffect.BULLET_SCALE_TYPE[bulletTrack] then
			comp:EnableScale(true,2.4)
		end

		if bulletTrack == LSkillEffConst.BULLET_LINEAR or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR or
				bulletTrack == LSkillEffConst.BULLET_LINEAR_THREE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE then
			comp:StartMove(bulletTarPos,flyTime,calcTime)
		else
			local traceType
			if bulletTrack == LSkillEffConst.BULLET_CURVE_ONE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_ONE then
				traceType = 1
			elseif bulletTrack == LSkillEffConst.BULLET_CURVE_TWO or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_TWO then
				traceType = 2
			end

			local tarPos = dpTrans.position
			local topPos,bulletTarPos = self:CalcCurvePos(traceType,tarPos,bulletTarPos)
			comp:StartJump(bulletTarPos, topPos, flyTime, calcTime)

			if calcTime > 0 then
				--为了让角度平滑 过度，预演 前一帧位置
				local t = 1
				if flyTime > 0 then t = calcTime / flyTime end
				t = t - 0.03
				if t < 0 then t = 0 end
				dpTrans.position = comp:GetPoint(t)
			end
		end

		comp:UpdatePos()
	end
end

function LFightIdleEffect:CalcCurvePos(traceType,tarPos,bulletTarPos)
	if(traceType == 1) then
		return self:CalcCurvePosOne(tarPos,bulletTarPos)
	elseif(traceType == 2) then
		return self:CalcCurvePosTwo(tarPos,bulletTarPos)
	end
	return tarPos,bulletTarPos
end

function LFightIdleEffect:CalcCurvePosOne(tarPos,bulletTarPos)
	local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  2 / 3)
	local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
	local offectY = Vector3.Distance(tarPos, bulletTarPos)
	local topPos = Vector3(topPosX,topPosY + offectY,0)
	return topPos,bulletTarPos
end

function LFightIdleEffect:CalcCurvePosTwo(tarPos,bulletTarPos)
	local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  1 / 2)
	local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
	local offectY
	local isUp = self._bulletIndex % 2 == 1
	if isUp then
		offectY = math.random(0,15) * 0.1
	else
		offectY = math.random(-15,0) * 0.1
	end

	local topPos = Vector3(topPosX,topPosY + offectY,0)

	return topPos,bulletTarPos
end

function LFightIdleEffect:SetPosition(pos)
	if not self._dp:IsDpValid() then return end
	local dpTrans = self._dp:GetDisplayTrans()
	dpTrans.position = Vector3(pos.x,pos.y,pos.z)
end

function LFightIdleEffect:SetSpeedUpVal(speedUp)
	self._speedUp = speedUp
end

function LFightIdleEffect:UpdateTimeScale(timeScale)
	if not self._dp:IsDpValid() then return end
	local dpTrans = self._dp:GetDisplayTrans()
	local animatorList = dpTrans:GetComponentsInChildren(typeofAnimator, true)
	local particleSystemList = dpTrans:GetComponentsInChildren(typeofParticleSystem, true)
	local skeletonAnimationList = dpTrans:GetComponentsInChildren(typeOfSkeletonAnimation, true)

	local animatorLen = animatorList.Length
	for k = 1, animatorLen do
		local animator = animatorList[k-1]
		animator.speed = timeScale
	end

	local particleSystemLen = particleSystemList.Length
	for k = 1, particleSystemLen do
		local particleSystem = particleSystemList[k-1]
		local mainModule = particleSystem.main
		if mainModule then
			mainModule.simulationSpeed = timeScale
		end
	end

	local skeletonAniLen = skeletonAnimationList.Length
	for k = 1, skeletonAniLen do
		local skeletonAni = skeletonAnimationList[k-1]
		skeletonAni.timeScale = timeScale
	end
end

function LFightIdleEffect:Destroy()
	if self._isDestroy then return end
	if self._dp then
		self._dp:Destroy()
		self._dp = nil
	end
	if self._pdp then
		if not self._pdp:IsDestroy() then
			self._pdp:Destroy()
		end
		self._pdp = nil
	end
	table.removeall(self)
	self._isDestroy = true
end
-----------------------------------------------------------------
function LFightIdleEffect:OnRun(time)
	if self._isDestroy then return false end
	if not self._isPlaying then
		if self._startTime <= time then
			self:PlayEffect()
		end
	else
		if self._dissipateTime < time then
			return false
		end
	end
	return true
end

function LFightIdleEffect:GetTime()
	return self._manager:GetTime()
end


function LFightIdleEffect:TimePause()
	if not self._dp:IsDpValid() then return end
	local dpTrans = self._dp:GetDisplayTrans()
	local comp = dpTrans:GetComponent(typeofBtObjectView)
	if not comp then
		return
	end

	comp:TimePause()
end
function LFightIdleEffect:TimeResume()
	if not self._dp:IsDpValid() then return end
	local dpTrans = self._dp:GetDisplayTrans()
	local comp = dpTrans:GetComponent(typeofBtObjectView)
	if not comp then
		return
	end

	comp:TimeResume()
end
-----------------------------------------------------------------
function LFightIdleEffect:DoPlayEffect(bPlay)
	self._pdp:SetVisible(bPlay) --skeletonAnimation 的 AnimationState 需要在Unity.Start之后

	if not self._pdp:IsDpValid() then return end

	self._pdp:InitRendererInfo()

	if bPlay then
		self._pdp:ResetPlayState()
	else
		self._pdp:ClearOldPlayState()
	end

	local rendererList = self._pdp:GetRendererList() or {}
	local rendererLayerList = self._pdp:GetRendererLayerList() or {}
	local rendererLen = #rendererList
	for k = 1, rendererLen do
		local renderer = rendererList[k]
		if bPlay then
			local layer = rendererLayerList[k]
			if layer then
				renderer.sortingLayerName = layer
			end
		else
			renderer.sortingLayerName = "Default"
		end
	end
end

function LFightIdleEffect:PreloadEffect(endFunc)
	if self._isPlaying then return end
	self._isPreloaded = false
	local dp = LDisplayEffect:New()
	self._pdp = dp
	dp:CreateEffect(self._parentTrans,self._effectName)
	dp:SetResTag(CS.RES_TAG_SCENE)
	dp:SetLoadedFunction(function()
		self:OnEffectPreloaded()
		if endFunc then
			endFunc(self._index)
		end
	end)
	dp:StartLoadEffect()

end

function LFightIdleEffect:OnEffectPreloaded()
	self._isPreloaded = true
	if self._isPlaying then
		self:OnEffectLoaded()
		return
	end

	self:DoPlayEffect(false)
end


-----------------------------------------------------------------
return LFightIdleEffect


